16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const nx = x + dx;
21	      const ny = y + dy;
22	      const k = cellKey(nx, ny);
23	      const entry = neighborCounts.get(k);
24	      if (entry) entry.count++;
25	      else neighborCounts.set(k, { cell: [nx, ny], count: 1 });
26	    }
27	  }
28	
29	  const result: Cell[] = [];
30	  for (const [k, { cell, count }] of neighborCounts) {
31	    if (survives(liveSet.has(k), count)) result.push(cell);
32	  }
33	  return result;
34	}
