export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const candidates = new Map<string, Cell>();
  const counts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor[0], neighbor[1]);
      candidates.set(k, neighbor);
      counts.set(k, (counts.get(k) ?? 0) + 1);
    }
  }

  return [...candidates].filter(([k, _]) =>
    survives(liveSet.has(k), counts.get(k)!)
  ).map(([, cell]) => cell);
}

